def singleton(cls):
    """
    Singleton deseni için bir dekoratör.
    """
    instances = {}

    def get_instance(*args, **kwargs):
        if cls not in instances:
            instances[cls] = cls(*args, **kwargs)
        return instances[cls]

    return get_instance

if __name__ == '__main__':
    @singleton
    class MyClass:
        def __init__(self, value):
            self.value = value

        def get_value(self):
            return self.value

    # Singleton örneğini oluştur
    instance1 = MyClass(10)
    instance2 = MyClass(20)

    # Her iki değişkenin de aynı nesneye işaret ettiğini kontrol et
    print(instance1 is instance2)  # True

    # Değerlerin aynı örneğin değerlerini değiştirdiğini kontrol et
    print(instance1.get_value())  # 10
    print(instance2.get_value())  # 10

    instance1.value = 30
    print(instance1.get_value())  # 30
    print(instance2.get_value())  # 30

    @singleton
    class AnotherClass:
        def __init__(self, value):
            self.value = value

        def get_value(self):
            return self.value

    instance3 = AnotherClass(5)
    instance4 = AnotherClass(8)

    print(instance3 is instance4) # True
    print(instance3.get_value()) # 5
    print(instance4.get_value()) # 5
